#####----- Figure 1. AF and AD select different ligand sets -----#####
# This shows AF-only, shared, and AD-only ligands for each protein.
# One row per method / strain / protein / ligand
ligand_sets <- complex_df %>%
  filter(status == "success") %>%
  distinct(method, strain, protein, EBC_ID)

# Shared ligands for each strain-protein pair
overlap_df <- ligand_sets %>%
  group_by(strain, protein, EBC_ID) %>%
  summarise(n_methods = n_distinct(method), .groups = "drop") %>%
  group_by(strain, protein) %>%
  summarise(
    shared = sum(n_methods == 2),
    .groups = "drop"
  )

method_counts <- ligand_sets %>%
  group_by(strain, protein, method) %>%
  summarise(n_ligands = n_distinct(EBC_ID), .groups = "drop") %>%
  pivot_wider(
    names_from = method,
    values_from = n_ligands,
    values_fill = 0
  )

overlap_full <- method_counts %>%
  left_join(overlap_df, by = c("strain", "protein")) %>%
  mutate(
    shared = replace_na(shared, 0),
    AF_only = AF - shared,
    AD_only = AD - shared,
    union = AF + AD - shared,
    jaccard = shared / union
  )

# Average across strains for compact main plot
overlap_protein <- overlap_full %>%
  group_by(protein) %>%
  summarise(
    AF_only = mean(AF_only),
    Shared = mean(shared),
    AD_only = mean(AD_only),
    mean_jaccard = mean(jaccard),
    .groups = "drop"
  )

overlap_long <- overlap_protein %>%
  select(protein, `AD only` = AD_only, Shared, `AF only` = AF_only) %>%
  pivot_longer(
    cols = c("AD only", "Shared", "AF only"),
    names_to = "category",
    values_to = "n"
  ) %>%
  mutate(
    category = factor(category, levels = c("AD only", "Shared", "AF only"))
  )

p1a <- ggplot(overlap_long, aes(x = protein, y = n, fill = category)) +
  geom_col(width = 0.72, color = "black", linewidth = 0.1) +
  scale_fill_manual(values = set_cols) +
  labs(
    x = NULL,
    y = "Mean no. of ligands",
    title = "Top-100 ligand overlap"
  ) +
  theme_nature_small(base_size = 10) +
  theme(
    axis.text.x = element_text(angle = 90, hjust = 1),
    legend.position = "top"
  )
