#####----- Figure 2. AF and AD interaction-type profiles for all top-100 ligands -----#####
# This is your back-to-back barplot idea.
# makes one small plot per protein
plot_interaction_back_to_back <- function(protein_id,
                                          strain_filter = NULL,
                                          shared_only = FALSE,
                                          title_prefix = "All top-100 ligands") {
  
  df <- counts_df %>%
    filter(protein == protein_id)
  
  if (!is.null(strain_filter)) {
    df <- df %>% filter(strain == strain_filter)
  }
  
  if (shared_only) {
    shared_keys <- complex_df %>%
      filter(status == "success") %>%
      distinct(method, strain, protein, EBC_ID) %>%
      group_by(strain, protein, EBC_ID) %>%
      summarise(n_methods = n_distinct(method), .groups = "drop") %>%
      filter(n_methods == 2) %>%
      select(strain, protein, EBC_ID)
    
    df <- df %>%
      semi_join(shared_keys, by = c("strain", "protein", "EBC_ID"))
  }
  
  plot_df <- df %>%
    group_by(method, interaction_type) %>%
    summarise(
      mean_count = mean(count, na.rm = TRUE),
      total_count = sum(count, na.rm = TRUE),
      n_complexes = n(),
      .groups = "drop"
    ) %>%
    mutate(
      signed_mean = if_else(method == "AD", -mean_count, mean_count),
      interaction_type = factor(interaction_type, levels = rev(interaction_levels))
    )
  
  max_x <- max(abs(plot_df$signed_mean), na.rm = TRUE)
  
  ggplot(plot_df, aes(x = signed_mean, y = interaction_type, fill = method)) +
    geom_col(width = 0.68, color = "black", linewidth = 0.12) +
    geom_vline(xintercept = 0, linewidth = 0.35) +
    scale_fill_manual(values = method_cols) +
    scale_x_continuous(
      limits = c(-max_x * 1.15, max_x * 1.15),
      labels = function(x) abs(x)
    ) +
    scale_y_discrete(labels = interaction_labels) +
    labs(
      x = "Mean interactions per ligand",
      y = NULL,
      title = paste0(title_prefix, ": ", protein_id)
    ) +
    theme_nature_small(base_size = 9) +
    theme(
      legend.position = "top",
      plot.title = element_text(size = 9, face = "bold")
    )
}

