#####----- Figure 4. Interaction fingerprint and residue-contact similarity -----#####
# This tests whether the same ligand has similar or different binding fingerprints between AF and AD.
# 4A. Interaction-type fingerprint similarity
calc_cosine <- function(a, b) {
  a <- as.numeric(a)
  b <- as.numeric(b)
  denom <- sqrt(sum(a^2)) * sqrt(sum(b^2))
  if (denom == 0) return(NA_real_)
  sum(a * b) / denom
}

calc_bray_curtis <- function(a, b) {
  a <- as.numeric(a)
  b <- as.numeric(b)
  denom <- sum(a + b)
  if (denom == 0) return(NA_real_)
  sum(abs(a - b)) / denom
}

fp_df <- counts_df %>%
  semi_join(shared_keys, by = c("strain", "protein", "EBC_ID")) %>%
  group_by(method, strain, protein, EBC_ID, interaction_type) %>%
  summarise(count = sum(count, na.rm = TRUE), .groups = "drop") %>%
  complete(
    method,
    strain,
    protein,
    EBC_ID,
    interaction_type = factor(interaction_levels, levels = interaction_levels),
    fill = list(count = 0)
  ) %>%
  unite("method_interaction", method, interaction_type, remove = FALSE) %>%
  select(strain, protein, EBC_ID, method_interaction, count) %>%
  pivot_wider(
    names_from = method_interaction,
    values_from = count,
    values_fill = 0
  )

# Add missing columns if any interaction type is absent
for (itype in interaction_levels) {
