    col <- paste(m, itype, sep = "_")
    if (!col %in% colnames(fp_df)) {
      fp_df[[col]] <- 0
    }
  }
}

ad_cols <- paste("AD", interaction_levels, sep = "_")
af_cols <- paste("AF", interaction_levels, sep = "_")

fp_sim <- fp_df %>%
  rowwise() %>%
  mutate(
    fingerprint_cosine = calc_cosine(c_across(all_of(ad_cols)), c_across(all_of(af_cols))),
    fingerprint_bray_curtis = calc_bray_curtis(c_across(all_of(ad_cols)), c_across(all_of(af_cols)))
  ) %>%
  ungroup() %>%
  mutate(
    protein = factor(protein, levels = protein_levels)
  )

p4a <- ggplot(fp_sim, aes(x = protein, y = fingerprint_cosine)) +
