# 4B. Residue-contact rewiring
# This asks: does the same ligand contact the same residues in AF and AD?
calc_jaccard <- function(x, y) {
  x <- unique(na.omit(x))
  y <- unique(na.omit(y))
  x <- x[x != ""]
  y <- y[y != ""]
  
  u <- union(x, y)
  if (length(u) == 0) return(NA_real_)
  
  length(intersect(x, y)) / length(u)
}

res_sets <- inter_df %>%
  semi_join(shared_keys, by = c("strain", "protein", "EBC_ID")) %>%
  filter(!is.na(protein_residue), protein_residue != "") %>%
  mutate(
    residue_contact = protein_residue,
    residue_interaction_contact = paste(protein_residue, interaction_type, sep = "|")
  ) %>%
  group_by(method, strain, protein, EBC_ID) %>%
  summarise(
    residue_set = list(unique(residue_contact)),
    residue_interaction_set = list(unique(residue_interaction_contact)),
    .groups = "drop"
  ) %>%
  pivot_wider(
    names_from = method,
    values_from = c(residue_set, residue_interaction_set)
  )

